/**
 * Notification log model — types for tracking sent notification history.
 *
 * Architecture: Event-Driven Notification Logging
 * =================================================
 * The NotificationHistoryService subscribes to notification lifecycle events
 * (notification:sent, notification:failed) via the EventBus and persists
 * log entries through the NotificationLogRepository.
 *
 * This captures a complete audit trail of all notification delivery attempts
 * without modifying the core NotificationService.
 *
 * Flow:
 *   NotificationService → EventBus(notification:sent/failed) → NotificationHistoryService → NotificationLogRepository
 *
 * Constraints:
 * - Logs are append-only — once created, they are never modified.
 * - Every sent or failed notification generates exactly one log entry.
 * - Log entries capture: recipient, channel, type (notification category), timestamp, and delivery status.
 */

import type { NotificationType, NotificationStatus, NotificationPriority } from './notification.js';

/**
 * Delivery status for a notification log entry.
 * Mirrors the terminal states from NotificationStatus.
 */
export type DeliveryStatus = 'delivered' | 'failed';

/**
 * A single notification log entry representing a delivery attempt.
 * Created by the NotificationHistoryService when a notification:sent or
 * notification:failed event is received.
 */
export interface NotificationLog {
  /** Unique log entry identifier (e.g., "nlog-0001") */
  id: string;
  /** The notification ID that was sent/failed */
  notificationId: string;
  /** Target recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Delivery channel used (email, webhook, in_app) */
  channel: NotificationType;
  /** Notification subject / summary */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority of the notification */
  priority: NotificationPriority;
  /** Whether the notification was delivered or failed */
  deliveryStatus: DeliveryStatus;
  /** Error message if delivery failed (undefined if delivered) */
  errorMessage?: string;
  /** Timestamp when the delivery was attempted */
  timestamp: Date;
  /** Optional metadata from the original notification */
  metadata?: Record<string, string>;
}

/**
 * Input for creating a notification log entry.
 * Omits the auto-generated `id` field.
 */
export interface CreateNotificationLogInput {
  notificationId: string;
  recipient: string;
  channel: NotificationType;
  subject: string;
  body: string;
  priority: NotificationPriority;
  deliveryStatus: DeliveryStatus;
  errorMessage?: string;
  timestamp: Date;
  metadata?: Record<string, string>;
}

/**
 * Query parameters for filtering notification history.
 * All filters are optional and combined with AND logic.
 */
export interface NotificationLogQuery {
  /** Filter by recipient identifier */
  recipient?: string;
  /** Filter by delivery channel */
  channel?: NotificationType;
  /** Filter by delivery status */
  deliveryStatus?: DeliveryStatus;
  /** Filter logs from this date onward (inclusive) */
  startDate?: Date;
  /** Filter logs up to this date (inclusive) */
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 * Supports filtering by recipient, channel, delivery status, and date range.
 *
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  NotificationLog,
  DeliveryStatus,
  NotificationLogQuery,
} from '../models/notification-log.js';
import type { NotificationType, NotificationPriority } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      priority: record['priority'] as NotificationPriority,
      deliveryStatus: record['deliveryStatus'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
    };

    if (record['errorMessage']) {
      log.errorMessage = record['errorMessage'] as string;
    }

    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, string>;
    }

    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      subject: entity.subject,
      body: entity.body,
      priority: entity.priority,
      deliveryStatus: entity.deliveryStatus,
      timestamp: entity.timestamp.toISOString(),
    };

    if (entity.errorMessage !== undefined) {
      record['errorMessage'] = entity.errorMessage;
    }

    if (entity.metadata !== undefined) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }

    return record;
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs for a specific channel.
   */
  findByChannel(channel: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Find all logs with a specific delivery status.
   */
  findByDeliveryStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.deliveryStatus === status);
  }

  /**
   * Find all logs within a date range (inclusive).
   */
  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.timestamp >= startDate && log.timestamp <= endDate,
    );
  }

  /**
   * Query logs with multiple optional filters (AND logic).
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) {
        return false;
      }
      if (filters.channel && log.channel !== filters.channel) {
        return false;
      }
      if (filters.deliveryStatus && log.deliveryStatus !== filters.deliveryStatus) {
        return false;
      }
      if (filters.startDate && log.timestamp < filters.startDate) {
        return false;
      }
      if (filters.endDate && log.timestamp > filters.endDate) {
        return false;
      }
      return true;
    });
  }

  /**
   * Find log by the original notification ID.
   */
  findByNotificationId(notificationId: string): NotificationLog | undefined {
    const results = this.findAll((log) => log.notificationId === notificationId);
    return results[0];
  }
}

/**
 * Notification history service — tracks and queries sent notification history.
 *
 * ARCHITECTURE: Event-Driven Logging
 * ====================================
 *
 * This service integrates with the existing notification flow by subscribing to
 * notification lifecycle events via the EventBus. It does NOT modify the
 * NotificationService — instead, it listens to events that are already emitted:
 *
 *   1. notification:sent   → logs a "delivered" entry
 *   2. notification:failed → logs a "failed" entry
 *
 * Flow:
 *   NotificationService
 *       ↓ (emits notification:sent / notification:failed)
 *   EventBus
 *       ↓
 *   NotificationHistoryService (this service)
 *       ↓
 *   NotificationLogRepository → Database
 *
 * This service also provides a rich query API to retrieve notification history
 * by recipient, channel, delivery status, and date range.
 *
 * CONSTRAINTS:
 * - All event subscriptions go through EventBus — no direct service calls.
 * - All data access goes through the NotificationLogRepository — no direct DB calls.
 * - Log entries are append-only — once created, they are never modified.
 * - Every notification:sent and notification:failed event generates one log entry.
 *
 * Depends on:
 * - EventBus for subscribing to notification lifecycle events.
 * - NotificationLogRepository for persisting log entries.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type {
  NotificationLog,
  NotificationLogQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationType } from '../models/notification.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private repository: NotificationLogRepository,
  ) {
    this.registerEventHandlers();
  }

  // ---------------------------------------------------------------------------
  // Event Handlers
  // ---------------------------------------------------------------------------

  /**
   * Register EventBus handlers for notification lifecycle events.
   *
   * CONSTRAINT: ALL event subscriptions MUST be registered here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.handleNotificationSent(event);
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.handleNotificationFailed(event);
    });
  }

  /**
   * Handle notification:sent event — create a "delivered" log entry.
   */
  private handleNotificationSent(event: NotificationSentEvent): void {
    this.logger.info(
      `Logging delivered notification: ${event.notification.id} via ${event.channel}`,
    );

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.notification.id,
      recipient: event.notification.recipient,
      channel: event.channel,
      subject: event.notification.subject,
      body: event.notification.body,
      priority: event.notification.priority,
      deliveryStatus: 'delivered',
      timestamp: event.timestamp,
      metadata: event.notification.metadata,
    };

    this.repository.save(log);
  }

  /**
   * Handle notification:failed event — create a "failed" log entry.
   */
  private handleNotificationFailed(event: NotificationFailedEvent): void {
    this.logger.info(
      `Logging failed notification: ${event.notification.id} via ${event.channel}: ${event.errorMessage}`,
    );

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.notification.id,
      recipient: event.notification.recipient,
      channel: event.channel,
      subject: event.notification.subject,
      body: event.notification.body,
      priority: event.notification.priority,
      deliveryStatus: 'failed',
      errorMessage: event.errorMessage,
      timestamp: event.timestamp,
      metadata: event.notification.metadata,
    };

    this.repository.save(log);
  }

  // ---------------------------------------------------------------------------
  // Query API
  // ---------------------------------------------------------------------------

  /**
   * Get all notification log entries.
   */
  getLogs(): NotificationLog[] {
    return this.repository.findAll();
  }

  /**
   * Get the total number of log entries.
   */
  getLogCount(): number {
    return this.repository.count();
  }

  /**
   * Get a specific log entry by ID.
   */
  getLogById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the log entry for a specific notification ID.
   */
  getLogByNotificationId(notificationId: string): NotificationLog | undefined {
    return this.repository.findByNotificationId(notificationId);
  }

  /**
   * Get all log entries for a specific recipient.
   *
   * @param recipient - The recipient identifier (email, user ID, URL, etc.)
   * @returns All log entries for the recipient, ordered by insertion.
   */
  getLogsByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries for a specific delivery channel.
   *
   * @param channel - The notification channel (email, webhook, in_app).
   * @returns All log entries for the channel.
   */
  getLogsByChannel(channel: NotificationType): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Get all log entries with a specific delivery status.
   *
   * @param status - The delivery status (delivered or failed).
   * @returns All log entries with the given status.
   */
  getLogsByDeliveryStatus(status: DeliveryStatus): NotificationLog[] {
    return this.repository.findByDeliveryStatus(status);
  }

  /**
   * Get all log entries within a date range (inclusive).
   *
   * @param startDate - Start of the date range.
   * @param endDate - End of the date range.
   * @returns All log entries within the range.
   */
  getLogsByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Query notification history with multiple optional filters.
   * Filters are combined with AND logic.
   *
   * @param query - Filter parameters (all optional).
   * @returns Matching log entries.
   */
  queryLogs(query: NotificationLogQuery): NotificationLog[] {
    return this.repository.query(query);
  }
}

