import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import type { NotificationLog } from '../../src/models/notification-log.js';

describe('NotificationLogRepository', () => {
  let db: Database;
  let repo: NotificationLogRepository;

  const createLog = (overrides: Partial<NotificationLog> = {}): NotificationLog => ({
    id: 'nlog-0001',
    notificationId: 'notif-0001',
    recipient: 'alice@example.com',
    channel: 'email',
    subject: 'Test Subject',
    body: 'Test body',
    priority: 'normal',
    deliveryStatus: 'delivered',
    timestamp: new Date('2026-03-15T10:00:00Z'),
    ...overrides,
  });

  beforeEach(() => {
    db = new Database();
    repo = new NotificationLogRepository(db);
  });

  describe('CRUD operations', () => {
    it('should save and retrieve a log entry', () => {
      const log = createLog();
      repo.save(log);

      const found = repo.findById('nlog-0001');
      expect(found).toBeDefined();
      expect(found!.id).toBe('nlog-0001');
      expect(found!.notificationId).toBe('notif-0001');
      expect(found!.recipient).toBe('alice@example.com');
      expect(found!.channel).toBe('email');
      expect(found!.subject).toBe('Test Subject');
      expect(found!.body).toBe('Test body');
      expect(found!.priority).toBe('normal');
      expect(found!.deliveryStatus).toBe('delivered');
      expect(found!.timestamp).toEqual(new Date('2026-03-15T10:00:00Z'));
    });

    it('should save a log entry with error message', () => {
      const log = createLog({
        id: 'nlog-0002',
        deliveryStatus: 'failed',
        errorMessage: 'Connection refused',
      });
      repo.save(log);

      const found = repo.findById('nlog-0002');
      expect(found).toBeDefined();
      expect(found!.deliveryStatus).toBe('failed');
      expect(found!.errorMessage).toBe('Connection refused');
    });

    it('should save a log entry with metadata', () => {
      const log = createLog({
        id: 'nlog-0003',
        metadata: { template: 'order-confirmation', orderId: 'ORD-001' },
      });
      repo.save(log);

      const found = repo.findById('nlog-0003');
      expect(found).toBeDefined();
      expect(found!.metadata).toEqual({
        template: 'order-confirmation',
        orderId: 'ORD-001',
      });
    });

    it('should return undefined for non-existent log', () => {
      expect(repo.findById('nlog-9999')).toBeUndefined();
    });

    it('should find all logs', () => {
      repo.save(createLog({ id: 'nlog-0001' }));
      repo.save(createLog({ id: 'nlog-0002', recipient: 'bob@example.com' }));

      const all = repo.findAll();
      expect(all).toHaveLength(2);
    });

    it('should count logs', () => {
      expect(repo.count()).toBe(0);
      repo.save(createLog({ id: 'nlog-0001' }));
      expect(repo.count()).toBe(1);
      repo.save(createLog({ id: 'nlog-0002' }));
      expect(repo.count()).toBe(2);
    });

    it('should delete a log entry', () => {
      repo.save(createLog({ id: 'nlog-0001' }));
      expect(repo.delete('nlog-0001')).toBe(true);
      expect(repo.findById('nlog-0001')).toBeUndefined();
    });
  });

  describe('findByRecipient', () => {
    it('should find logs by recipient', () => {
      repo.save(createLog({ id: 'nlog-0001', recipient: 'alice@example.com' }));
      repo.save(createLog({ id: 'nlog-0002', recipient: 'bob@example.com' }));
      repo.save(createLog({ id: 'nlog-0003', recipient: 'alice@example.com' }));

      const aliceLogs = repo.findByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);

      const bobLogs = repo.findByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array when no logs match', () => {
      repo.save(createLog({ id: 'nlog-0001', recipient: 'alice@example.com' }));
      expect(repo.findByRecipient('nobody@example.com')).toHaveLength(0);
    });
  });

  describe('findByChannel', () => {
    it('should find logs by channel', () => {
      repo.save(createLog({ id: 'nlog-0001', channel: 'email' }));
      repo.save(createLog({ id: 'nlog-0002', channel: 'webhook' }));
      repo.save(createLog({ id: 'nlog-0003', channel: 'email' }));

      const emailLogs = repo.findByChannel('email');
      expect(emailLogs).toHaveLength(2);

      const webhookLogs = repo.findByChannel('webhook');
      expect(webhookLogs).toHaveLength(1);
    });
  });

  describe('findByDeliveryStatus', () => {
    it('should find logs by delivery status', () => {
      repo.save(createLog({ id: 'nlog-0001', deliveryStatus: 'delivered' }));
      repo.save(createLog({ id: 'nlog-0002', deliveryStatus: 'failed', errorMessage: 'Timeout' }));
      repo.save(createLog({ id: 'nlog-0003', deliveryStatus: 'delivered' }));

      const delivered = repo.findByDeliveryStatus('delivered');
      expect(delivered).toHaveLength(2);

      const failed = repo.findByDeliveryStatus('failed');
      expect(failed).toHaveLength(1);
      expect(failed[0]!.errorMessage).toBe('Timeout');
    });
  });

  describe('findByDateRange', () => {
    it('should find logs within date range', () => {
      repo.save(createLog({
        id: 'nlog-0001',
        timestamp: new Date('2026-03-10T10:00:00Z'),
      }));
      repo.save(createLog({
        id: 'nlog-0002',
        timestamp: new Date('2026-03-15T10:00:00Z'),
      }));
      repo.save(createLog({
        id: 'nlog-0003',
        timestamp: new Date('2026-03-20T10:00:00Z'),
      }));

      const results = repo.findByDateRange(
        new Date('2026-03-12T00:00:00Z'),
        new Date('2026-03-18T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]!.id).toBe('nlog-0002');
    });

    it('should include logs at range boundaries', () => {
      const exactDate = new Date('2026-03-15T10:00:00Z');
      repo.save(createLog({ id: 'nlog-0001', timestamp: exactDate }));

      const results = repo.findByDateRange(exactDate, exactDate);
      expect(results).toHaveLength(1);
    });
  });

  describe('findByNotificationId', () => {
    it('should find log by notification ID', () => {
      repo.save(createLog({ id: 'nlog-0001', notificationId: 'notif-0001' }));
      repo.save(createLog({ id: 'nlog-0002', notificationId: 'notif-0002' }));

      const result = repo.findByNotificationId('notif-0001');
      expect(result).toBeDefined();
      expect(result!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent notification ID', () => {
      expect(repo.findByNotificationId('notif-9999')).toBeUndefined();
    });
  });

  describe('query', () => {
    beforeEach(() => {
      repo.save(createLog({
        id: 'nlog-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        deliveryStatus: 'delivered',
        timestamp: new Date('2026-03-10T10:00:00Z'),
      }));
      repo.save(createLog({
        id: 'nlog-0002',
        recipient: 'bob@example.com',
        channel: 'webhook',
        deliveryStatus: 'failed',
        errorMessage: 'Timeout',
        timestamp: new Date('2026-03-15T10:00:00Z'),
      }));
      repo.save(createLog({
        id: 'nlog-0003',
        recipient: 'alice@example.com',
        channel: 'webhook',
        deliveryStatus: 'delivered',
        timestamp: new Date('2026-03-20T10:00:00Z'),
      }));
    });

    it('should filter by recipient', () => {
      const results = repo.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by channel', () => {
      const results = repo.query({ channel: 'webhook' });
      expect(results).toHaveLength(2);
    });

    it('should filter by delivery status', () => {
      const results = repo.query({ deliveryStatus: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]!.recipient).toBe('bob@example.com');
    });

    it('should filter by date range', () => {
      const results = repo.query({
        startDate: new Date('2026-03-12T00:00:00Z'),
        endDate: new Date('2026-03-18T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.id).toBe('nlog-0002');
    });

    it('should combine multiple filters with AND logic', () => {
      const results = repo.query({
        recipient: 'alice@example.com',
        channel: 'webhook',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.id).toBe('nlog-0003');
    });

    it('should return all logs with empty query', () => {
      const results = repo.query({});
      expect(results).toHaveLength(3);
    });

    it('should return empty array when no logs match all filters', () => {
      const results = repo.query({
        recipient: 'bob@example.com',
        deliveryStatus: 'delivered',
      });
      expect(results).toHaveLength(0);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type {
  NotificationSentEvent,
  NotificationFailedEvent,
} from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(eventBus, repository);
    resetLogIdCounter();
    resetNotificationIdCounter();
  });

  // ---------------------------------------------------------------------------
  // Event-driven logging
  // ---------------------------------------------------------------------------

  describe('event-driven logging', () => {
    it('should log a delivered notification on notification:sent event', async () => {
      const event: NotificationSentEvent = {
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Your order has been placed.',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date('2026-03-15T09:00:00Z'),
          sentAt: new Date('2026-03-15T09:00:01Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-03-15T09:00:01Z'),
      };

      await eventBus.emit(event);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.id).toBe('nlog-0001');
      expect(logs[0]!.notificationId).toBe('notif-0001');
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.subject).toBe('Order Confirmation');
      expect(logs[0]!.body).toBe('Your order has been placed.');
      expect(logs[0]!.priority).toBe('normal');
      expect(logs[0]!.deliveryStatus).toBe('delivered');
      expect(logs[0]!.errorMessage).toBeUndefined();
      expect(logs[0]!.timestamp).toEqual(new Date('2026-03-15T09:00:01Z'));
    });

    it('should log a failed notification on notification:failed event', async () => {
      const event: NotificationFailedEvent = {
        type: 'notification:failed',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Status Update',
          body: 'Your order has shipped.',
          channel: 'webhook',
          priority: 'high',
          status: 'failed',
          createdAt: new Date('2026-03-15T10:00:00Z'),
          errorMessage: 'Connection refused',
        },
        channel: 'webhook',
        errorMessage: 'Connection refused',
        timestamp: new Date('2026-03-15T10:00:01Z'),
      };

      await eventBus.emit(event);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.deliveryStatus).toBe('failed');
      expect(logs[0]!.errorMessage).toBe('Connection refused');
      expect(logs[0]!.channel).toBe('webhook');
      expect(logs[0]!.priority).toBe('high');
    });

    it('should log metadata from the notification', async () => {
      const event: NotificationSentEvent = {
        type: 'notification:sent',
        notification: {
          id: 'notif-0003',
          recipient: 'alice@example.com',
          subject: 'Test',
          body: 'Test body',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date(),
          sentAt: new Date(),
          metadata: { template: 'order-confirmation', orderId: 'ORD-001' },
        },
        channel: 'email',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getLogs();
      expect(logs[0]!.metadata).toEqual({
        template: 'order-confirmation',
        orderId: 'ORD-001',
      });
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Test 1',
          body: 'Body 1',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date(),
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      } satisfies NotificationSentEvent);

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Test 2',
          body: 'Body 2',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date(),
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      } satisfies NotificationSentEvent);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(2);
      expect(logs[0]!.id).toBe('nlog-0001');
      expect(logs[1]!.id).toBe('nlog-0002');
    });
  });

  // ---------------------------------------------------------------------------
  // Integration with NotificationService
  // ---------------------------------------------------------------------------

  describe('integration with NotificationService', () => {
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      // Both services share the same EventBus — NotificationService emits,
      // NotificationHistoryService listens.
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
    });

    it('should log notifications sent through NotificationService.send()', async () => {
      await notificationService.send({
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
      });

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.deliveryStatus).toBe('delivered');
      expect(logs[0]!.subject).toBe('Order Confirmation');
    });

    it('should log failed notifications from NotificationService', async () => {
      // Send to a channel with no adapter registered
      await notificationService.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Webhook Test',
        body: 'Webhook body',
        channel: 'webhook',
      });

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.deliveryStatus).toBe('failed');
      expect(logs[0]!.errorMessage).toContain('No adapter registered');
    });

    it('should log notifications when adapter is unavailable', async () => {
      const disabledAdapter = new EmailAdapter({ enabled: false });
      notificationService.registerAdapter(disabledAdapter);

      await notificationService.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
      });

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.deliveryStatus).toBe('failed');
      expect(logs[0]!.errorMessage).toContain('not available');
    });

    it('should log multiple notifications from different channels', async () => {
      await notificationService.send({
        recipient: 'alice@example.com',
        subject: 'Email Test',
        body: 'Email body',
        channel: 'email',
      });

      await notificationService.send({
        recipient: 'https://hooks.example.com',
        subject: 'Webhook Test',
        body: 'Webhook body',
        channel: 'webhook',
      });

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(2);

      const emailLogs = historyService.getLogsByChannel('email');
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]!.deliveryStatus).toBe('delivered');

      const webhookLogs = historyService.getLogsByChannel('webhook');
      expect(webhookLogs).toHaveLength(1);
      expect(webhookLogs[0]!.deliveryStatus).toBe('failed');
    });
  });

  // ---------------------------------------------------------------------------
  // Query API
  // ---------------------------------------------------------------------------

  describe('query API', () => {
    beforeEach(async () => {
      // Populate with diverse log entries via events
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Your order has been placed.',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date('2026-03-10T09:00:00Z'),
          sentAt: new Date('2026-03-10T09:00:01Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-03-10T09:00:01Z'),
      } satisfies NotificationSentEvent);

      await eventBus.emit({
        type: 'notification:failed',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Webhook Notification',
          body: 'Status update.',
          channel: 'webhook',
          priority: 'high',
          status: 'failed',
          createdAt: new Date('2026-03-15T10:00:00Z'),
          errorMessage: 'Connection refused',
        },
        channel: 'webhook',
        errorMessage: 'Connection refused',
        timestamp: new Date('2026-03-15T10:00:01Z'),
      } satisfies NotificationFailedEvent);

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0003',
          recipient: 'alice@example.com',
          subject: 'Status Update',
          body: 'Your order has shipped.',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date('2026-03-20T14:00:00Z'),
          sentAt: new Date('2026-03-20T14:00:01Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-03-20T14:00:01Z'),
      } satisfies NotificationSentEvent);
    });

    it('should get all logs', () => {
      expect(historyService.getLogs()).toHaveLength(3);
    });

    it('should get log count', () => {
      expect(historyService.getLogCount()).toBe(3);
    });

    it('should get log by ID', () => {
      const log = historyService.getLogById('nlog-0001');
      expect(log).toBeDefined();
      expect(log!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent log ID', () => {
      expect(historyService.getLogById('nlog-9999')).toBeUndefined();
    });

    it('should get log by notification ID', () => {
      const log = historyService.getLogByNotificationId('notif-0002');
      expect(log).toBeDefined();
      expect(log!.recipient).toBe('bob@example.com');
    });

    it('should get logs by recipient', () => {
      const aliceLogs = historyService.getLogsByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);

      const bobLogs = historyService.getLogsByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      expect(historyService.getLogsByRecipient('nobody@example.com')).toHaveLength(0);
    });

    it('should get logs by channel', () => {
      const emailLogs = historyService.getLogsByChannel('email');
      expect(emailLogs).toHaveLength(2);

      const webhookLogs = historyService.getLogsByChannel('webhook');
      expect(webhookLogs).toHaveLength(1);

      const inAppLogs = historyService.getLogsByChannel('in_app');
      expect(inAppLogs).toHaveLength(0);
    });

    it('should get logs by delivery status', () => {
      const delivered = historyService.getLogsByDeliveryStatus('delivered');
      expect(delivered).toHaveLength(2);

      const failed = historyService.getLogsByDeliveryStatus('failed');
      expect(failed).toHaveLength(1);
      expect(failed[0]!.errorMessage).toBe('Connection refused');
    });

    it('should get logs by date range', () => {
      const results = historyService.getLogsByDateRange(
        new Date('2026-03-12T00:00:00Z'),
        new Date('2026-03-18T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]!.notificationId).toBe('notif-0002');
    });

    it('should query with multiple filters', () => {
      const results = historyService.queryLogs({
        recipient: 'alice@example.com',
        deliveryStatus: 'delivered',
      });
      expect(results).toHaveLength(2);
    });

    it('should query by channel and status', () => {
      const results = historyService.queryLogs({
        channel: 'webhook',
        deliveryStatus: 'failed',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.recipient).toBe('bob@example.com');
    });

    it('should query by recipient and date range', () => {
      const results = historyService.queryLogs({
        recipient: 'alice@example.com',
        startDate: new Date('2026-03-15T00:00:00Z'),
        endDate: new Date('2026-03-25T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.subject).toBe('Status Update');
    });

    it('should return all logs with empty query', () => {
      expect(historyService.queryLogs({})).toHaveLength(3);
    });

    it('should return empty array when no logs match combined filters', () => {
      const results = historyService.queryLogs({
        recipient: 'bob@example.com',
        deliveryStatus: 'delivered',
      });
      expect(results).toHaveLength(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Edge cases
  // ---------------------------------------------------------------------------

  describe('edge cases', () => {
    it('should handle log count when empty', () => {
      expect(historyService.getLogCount()).toBe(0);
      expect(historyService.getLogs()).toHaveLength(0);
    });

    it('should persist logs through the repository', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Test',
          body: 'Body',
          channel: 'email',
          priority: 'normal',
          status: 'sent',
          createdAt: new Date(),
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      } satisfies NotificationSentEvent);

      // Verify the log is persisted in the repository directly
      const repoLogs = repository.findAll();
      expect(repoLogs).toHaveLength(1);
      expect(repoLogs[0]!.notificationId).toBe('notif-0001');
    });
  });
});

