+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+import type { NotificationLog } from '../../src/models/notification-log.js';
+
+describe('NotificationLogRepository', () => {
+  let db: Database;
+  let repo: NotificationLogRepository;
+
+  const createLog = (overrides: Partial<NotificationLog> = {}): NotificationLog => ({
+    id: 'nlog-0001',
+    notificationId: 'notif-0001',
+    recipient: 'alice@example.com',
+    channel: 'email',
+    subject: 'Test Subject',
+    body: 'Test body',
+    priority: 'normal',
+    deliveryStatus: 'delivered',
+    timestamp: new Date('2026-03-15T10:00:00Z'),
+    ...overrides,
+  });
+
+  beforeEach(() => {
+    db = new Database();
+    repo = new NotificationLogRepository(db);
+  });
+
+  describe('CRUD operations', () => {
+    it('should save and retrieve a log entry', () => {
+      const log = createLog();
+      repo.save(log);
+
+      const found = repo.findById('nlog-0001');
+      expect(found).toBeDefined();
+      expect(found!.id).toBe('nlog-0001');
+      expect(found!.notificationId).toBe('notif-0001');
+      expect(found!.recipient).toBe('alice@example.com');
+      expect(found!.channel).toBe('email');
+      expect(found!.subject).toBe('Test Subject');
+      expect(found!.body).toBe('Test body');
+      expect(found!.priority).toBe('normal');
+      expect(found!.deliveryStatus).toBe('delivered');
+      expect(found!.timestamp).toEqual(new Date('2026-03-15T10:00:00Z'));
+    });
+
+    it('should save a log entry with error message', () => {
+      const log = createLog({
+        id: 'nlog-0002',
+        deliveryStatus: 'failed',
+        errorMessage: 'Connection refused',
+      });
+      repo.save(log);
+
+      const found = repo.findById('nlog-0002');
+      expect(found).toBeDefined();
+      expect(found!.deliveryStatus).toBe('failed');
+      expect(found!.errorMessage).toBe('Connection refused');
+    });
+
+    it('should save a log entry with metadata', () => {
+      const log = createLog({
+        id: 'nlog-0003',
+        metadata: { template: 'order-confirmation', orderId: 'ORD-001' },
+      });
+      repo.save(log);
+
+      const found = repo.findById('nlog-0003');
+      expect(found).toBeDefined();
+      expect(found!.metadata).toEqual({
+        template: 'order-confirmation',
+        orderId: 'ORD-001',
+      });
+    });
+
+    it('should return undefined for non-existent log', () => {
+      expect(repo.findById('nlog-9999')).toBeUndefined();
+    });
+
+    it('should find all logs', () => {
+      repo.save(createLog({ id: 'nlog-0001' }));
+      repo.save(createLog({ id: 'nlog-0002', recipient: 'bob@example.com' }));
+
+      const all = repo.findAll();
+      expect(all).toHaveLength(2);
+    });
+
+    it('should count logs', () => {
+      expect(repo.count()).toBe(0);
+      repo.save(createLog({ id: 'nlog-0001' }));
+      expect(repo.count()).toBe(1);
+      repo.save(createLog({ id: 'nlog-0002' }));
+      expect(repo.count()).toBe(2);
+    });
+
+    it('should delete a log entry', () => {
+      repo.save(createLog({ id: 'nlog-0001' }));
+      expect(repo.delete('nlog-0001')).toBe(true);
+      expect(repo.findById('nlog-0001')).toBeUndefined();
+    });
+  });
+
+  describe('findByRecipient', () => {
+    it('should find logs by recipient', () => {
+      repo.save(createLog({ id: 'nlog-0001', recipient: 'alice@example.com' }));
+      repo.save(createLog({ id: 'nlog-0002', recipient: 'bob@example.com' }));
+      repo.save(createLog({ id: 'nlog-0003', recipient: 'alice@example.com' }));
+
